div.p:
c
fprintf(g_output, "[pid %d] +++ exited with %d +++\n",
pid, WEXITSTATUS(status));
pid_map_remove(&g_pid_map, pid);
num_active--;
// NO ptrace(PTRACE_SYSCALL) — process is gone
continue;  // → next waitpid(-1)

c
fprintf(g_output, "[pid %d] +++ killed by signal %d (%s) +++\n",
pid, WTERMSIG(status), strsignal(WTERMSIG(status)));
pid_map_remove(&g_pid_map, pid);
num_active--;
// NO ptrace(PTRACE_SYSCALL) — process is gone
continue;  // → next waitpid(-1)

c
// Always resume with signal = 0
ptrace(PTRACE_SYSCALL, pid, 0, 0);

c
pid_state_t *state = pid_map_get(&g_pid_map, pid);
state->in_syscall = !state->in_syscall;
handle_syscall_stop(pid, state);

c
// Resume with signal = 0
ptrace(PTRACE_SYSCALL, pid, 0, 0);

c
// Resume with signal = 0
ptrace(PTRACE_SYSCALL, pid, 0, 0);

c
// Resume with signal = 0 (suppress)
ptrace(PTRACE_SYSCALL, pid, 0, 0);

c
// Re-inject: deliver signal on resume
ptrace(PTRACE_SYSCALL, pid, 0, stop_sig);
